const items = $input.all();

const events = items.map(item => {
  const e = item.json;

  return {
    eventId: e.id || "",
    title: e.summary || "Untitled Event",
    location: e.location || "No location",
    start: e.start?.dateTime || e.start?.date || "",
    end: e.end?.dateTime || e.end?.date || "",
  };
});

const formatDate = (dateStr) => {
  if (!dateStr) return "";
  const [year, month, day] = dateStr.split("T")[0].split("-");
  const d = new Date(Number(year), Number(month) - 1, Number(day));
  return d.toLocaleDateString([], { month: "long", day: "numeric" });
};

const formatTime = (dateStr) => {
  if (!dateStr || !dateStr.includes("T")) return "";

  const timePart = dateStr.split("T")[1].slice(0, 5); // HH:MM
  let [hour, minute] = timePart.split(":").map(Number);

  const suffix = hour >= 12 ? "PM" : "AM";
  hour = hour % 12;
  if (hour === 0) hour = 12;

  return minute === 0
    ? `${hour}:00 ${suffix}`
    : `${hour}:${String(minute).padStart(2, "0")} ${suffix}`;
};

let message = "";

if (events.length === 0) {
  message = "No events found for that time period.";
} else if (events.length === 1) {
  const e = events[0];
  message = `You have 1 event on ${formatDate(e.start)}: ${e.title} at ${formatTime(e.start)} in ${e.location}.`;
} else {
  const date = formatDate(events[0].start);

  const eventList = events
    .map(e => `• ${e.title} at ${formatTime(e.start)} (${e.location})`)
    .join("\n");

  message = `You have ${events.length} events on ${date}:\n${eventList}`;
}

return [
  {
    json: {
      success: true,
      intent: "calendar",
      action: "get",
      eventsFound: events.length,
      events,
      message,
    }
  }
];

const messages = $input.all().map(item => {
  const j = item.json;

  return {
    id: j.id,
    threadId: j.threadId,
    subject: j.Subject || "",
    from: j.From || "",
    to: j.To || "",
    snippet: j.snippet || "",
    labels: (j.labels || []).map(label => label.name || label.id)
  };
});

return [
  {
    json: {
      success: true,
      intent: "email",
      action: "get_many_messages",
      count: messages.length,
      messages
    }
  }
];

